2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	
5	type QuoteStep = { op: string; items: Item[] };
6	
7	type Damage = { itemType: string; amount: number };
8	
9	type Incident = { cause: string; damages: Damage[] };
10	
11	type ClaimStep = { op: string; policy: number; incident: Incident };
12	
13	type Step = QuoteStep | ClaimStep;
14	
15	type Customer = { yearsWithMHPCO: number };
16	
17	type Scenario = {
18	  customer: Customer;
19	  steps: Step[];
20	};
21	
22	type QuoteResult = { premium: number };
23	
24	type ClaimResult = { payout: number; remainingCap: number };
25	
26	type StepResult = QuoteResult | ClaimResult;
27	
28	type ScenarioResult = {
29	  results: StepResult[];
30	};
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PROCESSING_FEE = 5;
43	
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	
49	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
51	
52	const LOYALTY_DISCOUNT_RATE = 0.2;
53	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
54	
55	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
56	
57	const DEDUCTIBLE = 100;
58	const PAYOUT_CAP_MULTIPLIER = 2;
59	
60	const INSURANCE_VALUES: Record<string, number> = {
61	  sword: 1000,
62	  amulet: 600,
63	  staff: 800,
64	  potion: 400,
65	  rune: 250,
66	  moonstone: 250,
67	};
68	
69	const countItemsByType = (items: Item[]): Map<string, number> => {
70	  const counts = new Map<string, number>();
71	  for (const item of items) {
72	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
73	  }
74	  return counts;
75	};
76	
77	const basePremiumForGroup = (type: string, count: number): number =>
78	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
79	
80	const calculateTotalBasePremium = (items: Item[]): number =>
81	  [...countItemsByType(items)].reduce(
82	    (total, [type, count]) => total + basePremiumForGroup(type, count),
83	    0,
84	  );
85	
86	const curseSurchargeForItem = (item: Item): number =>
87	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
88	
89	const enchantmentSurchargeForItem = (item: Item): number =>
90	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
91	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
92	    : 0;
93	
94	const sumSurcharges = (
95	  items: Item[],
96	  surchargeForItem: (item: Item) => number,
97	): number =>
98	  items.reduce((total, item) => total + surchargeForItem(item), 0);
99	
100	const policyDiscountRate = (customer: Customer, stepIndex: number): number => {
101	  const loyaltyDiscountRate =
102	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
103	      ? LOYALTY_DISCOUNT_RATE
104	      : 0;
105	  const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
106	  return loyaltyDiscountRate + followUpDiscountRate;
107	};
108	
109	const payoutCapForItems = (items: Item[]): number =>
110	  PAYOUT_CAP_MULTIPLIER *
111	  items.reduce((total, item) => total + INSURANCE_VALUES[item.type], 0);
112	
113	const claimStep = (step: ClaimStep, steps: Step[]): ClaimResult => {
114	  const policyItems = (steps[step.policy] as QuoteStep).items;
115	  const payoutCap = payoutCapForItems(policyItems);
116	  const payout = step.incident.damages[0].amount - DEDUCTIBLE;
117	  return {
118	    payout,
119	    remainingCap: payoutCap - payout,
120	  };
121	};
122	
123	const quoteStep = (
124	  step: QuoteStep,
125	  customer: Customer,
126	  stepIndex: number,
127	): QuoteResult => {
128	  const totalBasePremium = calculateTotalBasePremium(step.items);
129	  const firstInsuranceSurcharge =
130	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
131	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
132	  const enchantmentSurcharge = sumSurcharges(
133	    step.items,
134	    enchantmentSurchargeForItem,
135	  );
136	  const discount =
137	    totalBasePremium * policyDiscountRate(customer, stepIndex);
138	  return {
139	    premium: Math.ceil(
140	      totalBasePremium + firstInsuranceSurcharge + curseSurcharge +
141	        enchantmentSurcharge - discount + PROCESSING_FEE,
142	    ),
143	  };
144	};
145	
146	export const processScenario = (scenario: Scenario): ScenarioResult => ({
147	  results: scenario.steps.map((step, index) =>
148	    "incident" in step
149	      ? claimStep(step, scenario.steps)
150	      : quoteStep(step, scenario.customer, index),
151	  ),
152	});
