const DEDUCTIBLE = 100;
const PAYOUT_CAP_MULTIPLIER = 2;

const HIGH_ENCHANTMENT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;

const damage = step.incident.damages[0];
const damagedItem = policyItems.find(
  (item) => item.type === damage.itemType,
);
const reimbursement =
  (damagedItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
    : damage.amount;
const payout = reimbursement - DEDUCTIBLE;
